const contact = $input.item.json;

const changes = [];
const currentCompany = contact.linkedin_current_company || '';
const expectedCompany = contact.crm_company_name || '';
const currentTitle = contact.linkedin_title || '';
const previousTitle = contact.crm_title || '';

// Detect departure
if (currentCompany && expectedCompany && currentCompany.toLowerCase() !== expectedCompany.toLowerCase()) {
  changes.push({
    type: 'departure',
    severity: contact.role === 'champion' ? 'critical' : 'high',
    description: `${contact.name} left ${expectedCompany} → now at ${currentCompany}`,
    action: contact.role === 'champion' ? 'URGENT: Identify new champion immediately. Schedule exec sponsor call.' : 'Update CRM contact record. Identify replacement.'
  });
}

// Detect title/role change
if (currentTitle && previousTitle && currentTitle !== previousTitle && currentCompany.toLowerCase() === expectedCompany.toLowerCase()) {
  changes.push({
    type: 'role_change',
    severity: 'medium',
    description: `${contact.name} role changed: ${previousTitle} → ${currentTitle}`,
    action: 'Schedule check-in to understand new responsibilities and impact on partnership.'
  });
}

if (changes.length === 0) return [];

return changes.map(change => ({
  json: {
    account_id: contact.account_id,
    account_name: contact.account_name,
    contact_name: contact.name,
    contact_role: contact.role,
    change_type: change.type,
    severity: change.severity,
    description: change.description,
    recommended_action: change.action,
    csm_email: contact.csm_email,
    arr: contact.arr
  }
}));

const newContacts = $input.item.json.contacts || [];
const account = $input.item.json;

return newContacts
  .filter(c => ['VP', 'Director', 'C-Suite', 'Head of'].some(t => (c.title || '').includes(t)))
  .map(c => ({
    json: {
      account_id: account.account_id,
      account_name: account.account_name,
      contact_name: c.name,
      contact_role: 'new_executive',
      change_type: 'new_stakeholder',
      severity: 'medium',
      description: `New executive detected: ${c.name} (${c.title}) at ${account.account_name}`,
      recommended_action: 'Schedule introduction meeting. Add to stakeholder map. Brief on current partnership status.',
      csm_email: account.csm_email,
      arr: account.arr
    }
  }));
